"use client"

import { useState, useCallback, useEffect, useRef } from "react"
import { ChevronRight } from "lucide-react"
import { SearchBar } from "./search-bar"
import { TrackList } from "./track-list"
import { NowPlaying } from "./now-playing"
import { SettingsPanel } from "./settings-panel"
import { AuthPanel } from "./auth-panel"
import { searchTracks } from "../../lib/api"
import type { Track } from "../../lib/types"

interface MainContentProps {
  activeTab: string
}

export function MainContent({ activeTab }: MainContentProps) {
  const [searchQuery, setSearchQuery] = useState("")
  const [tracks, setTracks] = useState<Track[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState("")
  const [showNowPlaying, setShowNowPlaying] = useState(false)
  const tracksCache = useRef<Record<string, Track[]>>({})

  useEffect(() => {
    if (!searchQuery.trim()) {
      setTracks([])
      setError("")
      return
    }

    // Проверяем кеш
    if (tracksCache.current[searchQuery]) {
      setTracks(tracksCache.current[searchQuery])
      setError("")
      return
    }

    let isCancelled = false
    setIsLoading(true)
    setError("")

    searchTracks(searchQuery)
      .then((data) => {
        if (!isCancelled) {
          // Сохраняем в кеш
          tracksCache.current[searchQuery] = data
          setTracks(data)
        }
      })
      .catch((err: unknown) => {
        if (!isCancelled) {
          setError(err instanceof Error ? err.message : "Помилка при пошуку")
        }
      })
      .finally(() => {
        if (!isCancelled) {
          setIsLoading(false)
        }
      })

    return () => {
      isCancelled = true
    }
  }, [searchQuery])

  const handleSearch = useCallback((query: string) => {
    setSearchQuery(query)
  }, [])

  if (activeTab === "settings") {
    return (
      <div className="flex-1 p-6 overflow-y-auto">
        <SettingsPanel />
      </div>
    )
  }

  if (activeTab === "profile") {
    return (
      <div className="flex-1 p-6 overflow-y-auto">
        <h1 className="text-3xl text-white mb-6">Особистий кабінет</h1>
        <AuthPanel />
      </div>
    )
  }

  return (
    <div className="flex-1 flex overflow-hidden">
      {/* Main Track Area */}
      <div className="flex-1 p-8 overflow-y-auto relative">
        <SearchBar onSearch={handleSearch} />
        
        {/* Button to show Now Playing */}
        <button
          onClick={() => setShowNowPlaying(true)}
          className="absolute top-24 right-8 z-150 p-2 bg-white/10 hover:bg-white/15 rounded-lg text-white transition-all duration-200 hover:scale-110"
          title="Показати поточний трек"
        >
          <ChevronRight className="w-5 h-5" />
        </button>
        
        <div className="mt-8">
          {activeTab === "home" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Головна</h1>
              <TrackList tracks={tracks} title="Рекомендації" />
            </>
          )}
          
          {activeTab === "search" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Пошук</h1>
              {isLoading ? (
                <p className="text-white/50 text-lg">Завантаження результатів...</p>
              ) : error ? (
                <p className="text-red-400 text-lg">{error}</p>
              ) : (
                <TrackList 
                  tracks={tracks} 
                  title={searchQuery ? `Результати для "${searchQuery}"` : "Пошук музики"} 
                />
              )}
            </>
          )}
          
          {activeTab === "library" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Бібліотека</h1>
              <TrackList tracks={tracks} title="Нещодавно відтворені" />
            </>
          )}
          
          {activeTab === "liked" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Вподобані</h1>
              <TrackList tracks={tracks.slice(0, 3)} title="Твої улюблені треки" />
            </>
          )}
          
          {activeTab === "playlists" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Плейлисти</h1>
              <TrackList tracks={[]} />
            </>
          )}
          
          {activeTab === "radio" && (
            <>
              <h1 className="text-4xl font-bold text-white mb-8">Радіо</h1>
              <TrackList tracks={tracks.slice(2)} title="Радіостанції" />
            </>
          )}
        </div>
      </div>

      {/* Now Playing Modal/Drawer */}
      {showNowPlaying && (
        <div className="fixed inset-0 z-40 bg-black/50 backdrop-blur-sm lg:hidden">
          <div className="animate-in slide-in-from-right w-full max-w-md ml-auto h-full bg-white/8 backdrop-blur-xl border-l border-white/15 overflow-y-auto">
            <div className="p-6">
              <button
                onClick={() => setShowNowPlaying(false)}
                className="absolute top-4 left-4 p-2 text-white/60 hover:text-white transition-colors"
              >
                ✕
              </button>
              
              <h3 className="text-lg font-semibold text-white mb-6 mt-4">Зараз грає</h3>
              <NowPlaying />
              
              <div className="mt-8">
                <h3 className="text-lg font-semibold text-white mb-4">Черга</h3>
                <div className="bg-white/8 backdrop-blur-xl border border-white/15 rounded-2xl p-6">
                  <p className="text-white/40 text-center text-base font-medium">Черга пуста</p>
                  <p className="text-white/20 text-center text-sm mt-1">Додайте треки</p>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}        
      </div>
  )
}
